import * as PIXI from 'pixi.js';
import { Model } from './game/Model';
import { Menu } from './game/Menu';
import { Game } from './game/Game';
import { EventsManager } from './core/EventsManager';
import { ZScene } from 'zimporter-pixi/dist/ZScene';
import { ZSceneStack } from 'zimporter-pixi/dist/ZSceneStack';
import { ZContainer } from 'zimporter-pixi/dist/ZContainer';
import { MobileControls } from './game/MobileControls';

const LEFT_KEY = 'ArrowLeft';
const RIGHT_KEY = 'ArrowRight';
const UP_KEY = 'ArrowUp';
const DOWN_KEY = 'ArrowDown';
export class Main {

    private game: Game;
    private frame: PIXI.DisplayObject | null = null;
    private mobileControls: MobileControls | null = null;



    constructor(
        appStage: PIXI.Container,
        resizeCanvas: () => void,
        updatePreloader?: (per: number) => void,
        hidePreloader?: () => void
    ) {


        let loadPath = (window as any).loadPath || "./scene/";
        //console.log("Game constructor " + loadPath);
        let scene: ZScene = new ZScene("game-scene");
        scene.load(loadPath, () => {
            hidePreloader?.();
            ZSceneStack.push(scene);

            let stage = scene.sceneStage;
            scene.loadStage(appStage);
            Model.stage = stage;

            // Find the "frame" container and keep a reference so it stays on top
            this.frame = stage.get("hud") as PIXI.Container;



            resizeCanvas?.();

            // Show the logo splash and wait for any interaction before starting
            this.showSplash(() => {
                this.game = new Game();
                this.mobileControls = new MobileControls();
            });

        }, (progress: number) => {
            updatePreloader?.(progress);
        });
        //EventsManager.addListener('MENU_SPACE_PRESSED', game, onMenuSpacePressed);

        EventsManager.addListener('GAME_OVER', this.onGameOver.bind(this));

        window.addEventListener('keydown', (e) => {
            switch (e.key) {
                case LEFT_KEY:
                    Model.movement.left = true;
                    break;
                case RIGHT_KEY:
                    Model.movement.right = true;
                    break;
                case UP_KEY:
                    Model.movement.up = true;
                    break;
                case DOWN_KEY:
                    Model.movement.down = true;
                    break;
                case ' ':
                case 'Spacebar':
                    Model.movement.space = true;
                    EventsManager.emit('MENU_SPACE_PRESSED');
                    break;
            }
        });

        window.addEventListener('keyup', (e) => {
            switch (e.key) {
                case LEFT_KEY:
                    Model.movement.left = false;
                    break;
                case RIGHT_KEY:
                    Model.movement.right = false;
                    break;
                case UP_KEY:
                    Model.movement.up = false;
                    break;
                case DOWN_KEY:
                    Model.movement.down = false;
                    break;
                case ' ':
                case 'Spacebar':
                    Model.movement.space = false;
                    break;
            }
        });
    }

    onGameOver(obj: { win: boolean }) {
        this.game.onGameOver(() => {
            if (obj?.win) {
                Model.level = Model.level + 1;
                if (!Model.levels[Model.level]) {
                    // finished all levels — restart from the beginning
                    Model.level = 0;
                }
            } else {
                // lost — restart from level 0
                Model.level = 0;
            }
            this.game.init();
        }, obj?.win ?? false);
    }

    update(dt: number) {
        if (this.game) {
            this.game.update(dt);
        }
    }

    private showSplash(onDismiss: () => void) {
        const logo = Model.stage?.get('logo') as ZContainer | null;
        if (!logo) {
            // No logo asset — start immediately
            onDismiss();
            return;
        }

        logo.setVisible(true);

        // Make the whole stage interactive so any tap/click dismisses it
        (logo as any).eventMode = 'static';
        (logo as any).cursor = 'pointer';

        const dismiss = () => {
            logo.setVisible(false);
            (logo as any).off('pointerdown', dismiss);
            window.removeEventListener('keydown', onKey);
            onDismiss();
        };

        const onKey = () => dismiss();

        logo.on('pointerdown', dismiss);
        window.addEventListener('keydown', onKey, { once: true });
    }
}